import ldap

def search_users_ldap(ldap_server, bind_dn, bind_password, search_base, username):
    # Validate and sanitize input
    if not username or not isinstance(username, str):
        raise ValueError("Username must be a non-empty string")
    
    # Escape special LDAP characters to prevent injection
    escaped_username = ldap.filter.escape_filter_chars(username)
    
    # Construct the search filter
    search_filter = f"(uid={escaped_username})"
    
    try:
        # Initialize LDAP connection
        conn = ldap.initialize(ldap_server)
        conn.protocol_version = 3
        conn.simple_bind_s(bind_dn, bind_password)
        
        # Perform the search
        results = conn.search_s(
            search_base,
            ldap.SCOPE_SUBTREE,
            search_filter,
            ['uid', 'cn', 'mail', 'givenName', 'sn']
        )
        
        # Process results
        users = []
        for dn, attrs in results:
            if attrs:
                user = {
                    'dn': dn,
                    'uid': attrs.get('uid', [None])[0],
                    'cn': attrs.get('cn', [None])[0],
                    'mail': attrs.get('mail', [None])[0],
                    'givenName': attrs.get('givenName', [None])[0],
                    'sn': attrs.get('sn', [None])[0]
                }
                users.append(user)
        
        conn.unbind_s()
        return users
        
    except ldap.INVALID_CREDENTIALS:
        raise Exception("Invalid credentials")
    except ldap.LDAPError as e:
        raise Exception(f"LDAP error: {e}")